// ===== AGENT ACCUEIL — agrège les 4 JSON frais du matin =====
function get(n){ try{ return $(n).first().json; }catch(e){ return {}; } }
const tcgp=get('Frais tcgp'), classic=get('Frais classic'), vgc=get('Frais vgc'), unite=get('Frais unite');
const now=new Date(), iso=now.toISOString();
const jours=['dimanche','lundi','mardi','mercredi','jeudi','vendredi','samedi'];
const topU=(tcgp.topUsage)||[];
const mover=topU.find(d=>d.move==='up'||d.move==='new');
const spot=topU.length?topU[(now.getDate())%topU.length]:null;
const cTop=(classic.topUsage||[])[0];
const home={
 hero:{tag:'Hub Competitif Pokemon',title:"L'actu competitive en un seul endroit."},
 news:[
  {game:'tcgp',title:(mover?mover.name+" bouge dans la méta Pocket":(spot?spot.name+" — le point méta du "+jours[now.getDay()]:"Méta Pocket du jour")),
   desc:tcgp.metaSummary||'',when:'TCG Pocket',badgeText:'META',badgeStyle:'tcgp',clickAction:'tcgp'},
  {game:'vgc',title:((vgc.newsFeed||[])[0]||'VGC — état du format Champions').slice(0,80),
   desc:(vgc.metaSummary||'').slice(0,220),when:'Pokémon Champions',badgeText:'VGC',badgeStyle:'vgc',clickAction:'vgc'},
  {game:'classic',title:cTop?cTop.name+" à "+cTop.share+"% des points":'TCG Classic — le point format',
   desc:classic.metaSummary||'',when:'TCG Classic',badgeText:'CLASSIC',badgeStyle:'classic',clickAction:'classic'},
  {game:'unite',title:'Unite — tier list du jour',
   desc:(unite.metaSummary||'').slice(0,220),when:'Pokémon Unite',badgeText:'UNITE',badgeStyle:'unite',clickAction:'unite'}
 ],
 timeline:[
  {title:'Pokémon Champions mobile',desc:'Sortie iOS/Android le 17 juin',game:'vgc',date:'17 juin · VGC'},
  {title:'Mini-set B3b (estimé)',desc:'Le prochain catalyseur de la méta Pocket',game:'tcgp',date:'~10 juillet · TCG POCKET'}
 ],
 gamePreviews:{tcgp:true,vgc:true,classic:true,unite:true},
 updatedAt:iso };
return [{json:{content:JSON.stringify(home,null,2),msg:"bot(home) "+now.toLocaleDateString('fr-FR')+" : une = "+home.news[0].title}}];
